import xml.etree.ElementTree as ET

def parse_xml(file_path):
    settings = {}

    tree = ET.parse(file_path)
    root = tree.getroot()

    for element in root:
        key = element.tag
        value = ''.join([child.text for child in element])
        settings[key] = value

    return settings